import React from 'react';

const Navbar = () => {
  return (
    <nav>
      <ul>
        <li><a href="#about">אודותינו</a></li>
        <li><a href="#services">השירותים שלנו</a></li>
        <li><a href="#donate">תרומה</a></li>
        <li><a href="#contact">צור קשר</a></li>
      </ul>
    </nav>
  );
};

export default Navbar;
